// Get Gmail message data
const gmailMessages = $input.all();
// const leadData = $('Get Recent Outreach Emails').first().json;
const leadInfo = $('Test Data - Mock Outreach').first().json;
const replies = [];

for (const item of gmailMessages) {
  const message = item.json;

  // Extract email body
  let bodyText = '';

  // Gmail stores body in different formats
  if (message.payload.parts) {
    // Multi-part message
    for (const part of message.payload.parts) {
      if (part.mimeType === 'text/plain' && part.body.data) {
        bodyText += Buffer.from(part.body.data, 'base64').toString('utf-8');
      }
    }
  } else if (message.payload.body && message.payload.body.data) {
    // Simple message
    bodyText = Buffer.from(message.payload.body.data, 'base64').toString('utf-8');
  }

  // Extract subject
  const headers = message.payload.headers;
  const subject = headers.find(h => h.name === 'Subject')?.value || '';
  const from = headers.find(h => h.name === 'From')?.value || '';
  const date = headers.find(h => h.name === 'Date')?.value || '';

  // Clean body (remove quoted text, signatures)
  const cleanBody = cleanEmailBody(bodyText);

  replies.push({
    lead_id: leadInfo.lead_id,
    org_id: leadInfo.org_id,
    company_name: leadInfo.company_name,
    reply_from: from,
    reply_to: leadInfo.lead_email,
    subject: subject,
    body: cleanBody,
    full_body: bodyText,
    received_at: new Date(date).toISOString(),
    thread_id: message.threadId,
    message_id: message.id
  });
}

// Helper function to clean email body
function cleanEmailBody(body) {
  if (!body) return '';

  // Remove quoted text (lines starting with >)
  let lines = body.split('\n');
  lines = lines.filter(line => !line.trim().startsWith('>'));

  // Remove common signature markers
  const signatureMarkers = [
    'Sent from my iPhone',
    'Sent from my Android',
    'Get Outlook for',
    '---',
    'Best regards',
    'Thanks,',
    'Sincerely,'
  ];

  let cleaned = lines.join('\n');

  // Find first signature marker and cut there
  for (const marker of signatureMarkers) {
    const index = cleaned.indexOf(marker);
    if (index > 0) {
      cleaned = cleaned.substring(0, index);
      break;
    }
  }

  return cleaned.trim();
}

return replies;

const aiAnalysis = $input.first().json.output || {};
const replyData = $('Extract Reply Data').first().json;

// Parse AI response
const qualification = {
  // Lead info
  lead_id: replyData.lead_id,
  org_id: replyData.org_id,
  company_name: replyData.company_name,

  // Reply data
  reply_from: replyData.reply_from,
  reply_to: replyData.reply_to,
  subject: replyData.subject,
  body: replyData.body,
  received_at: replyData.received_at,
  thread_id: replyData.thread_id,

  // AI Analysis
  sentiment: aiAnalysis.sentiment || 'neutral',
  intent: aiAnalysis.intent || 'unknown',
  urgency: aiAnalysis.urgency || 'normal',
  budget_mentioned: aiAnalysis.budget_mentioned || false,
  budget_info: aiAnalysis.budget_info || null,
  timeline_mentioned: aiAnalysis.timeline_mentioned || null,
  pain_points_mentioned: aiAnalysis.pain_points || [],
  decision_maker_confirmed: aiAnalysis.decision_maker_confirmed || false,

  // Qualification
  qualification_score: aiAnalysis.qualification_score || 50,
  interest_level: aiAnalysis.interest_level || 'cold',
  next_action: aiAnalysis.next_action || 'nurture',

  // For sales team
  recommended_response: aiAnalysis.recommended_response || '',
  key_insights: aiAnalysis.key_insights || '',
  red_flags: aiAnalysis.red_flags || [],

  // Metadata
  ai_confidence: aiAnalysis.confidence || 0,
  processed: true,
  processed_at: new Date().toISOString()
};

// Determine qualification status
let qualificationStatus;
if (qualification.qualification_score >= 70) {
  qualificationStatus = 'qualified';
} else if (qualification.qualification_score >= 40) {
  qualificationStatus = 'warm';
} else if (qualification.sentiment === 'not_interested' || qualification.intent === 'unsubscribe') {
  qualificationStatus = 'disqualified';
} else {
  qualificationStatus = 'cold';
}

qualification.qualification_status = qualificationStatus;

// Determine if sales ready
qualification.sales_ready = (
  qualification.qualification_score >= 70 &&
  ['interested', 'question'].includes(qualification.sentiment) &&
  !['unsubscribe', 'decline'].includes(qualification.intent)
);

return qualification;

